  const topComments = [];
  for (let i = 0; i < Math.min(3, sorted.length); i++) { const p = sorted[i]; const comments = p.latestComments || p.comments_list || []; for (let j = 0; j < Math.min(7, comments.length); j++) { const c = comments[j]; topComments.push({ text: c.text||c.comment||'', likes: c.likesCount||c.likes||0, postUrl: p.url||'' }); } }
